\SQL CALC|01| PRO (
-- LESÃO: primeiro lançamento na ficha (arquivo/ficha), com sigla do evento + descrição
SELECT CONCAT(t.evento, ' - ', e.descricao) AS 'LESÃO'
FROM cad_processo p
JOIN cad_processo i
ON i.arquivo = p.arquivo
AND i.ficha = p.ficha
JOIN tramitacao t
ON t.id_processo = i.pj
LEFT JOIN tab_evento e
ON e.sigla = t.evento
WHERE p.pj = PRO.pj
AND t.evento IN ('FRA','AMPU','LUX','ROMP','QUEI','TRAUM','PSIQU','CANCE','ARTRO','SINDR')
and t.evento in ()
ORDER BY t.data_hora_lan ASC
LIMIT 1
)




