ORDER BY t.data_hora_lan ASC







SELECT
  CONCAT_WS(' | ', e.descricao, cid.evento) AS `LESÃO`,
  p.pj
FROM cad_processo p
JOIN cad_processo i
  ON i.arquivo = p.arquivo
 AND i.ficha   = p.ficha

/* LESÃO: deixa como LEFT, e filtra no ON */
LEFT JOIN tramitacao t
  ON t.id_processo = i.pj
 AND t.evento IN ('FRA','AMPU','LUX','ROMP','QUEI','TRAUM','PSIQU','CANCE','ARTRO','SINDR')

LEFT JOIN tab_evento e
  ON e.sigla = t.evento

